class Solution:
    def missingInteger(self, nums):
        run_len = 1
        for i in range(1, len(nums)):
            if nums[i] == nums[i - 1] + 1:
                run_len += 1
            else:
                break
        total = sum(nums[:run_len])
        x = total
        while x in nums:
            x += 1
        return x

