class Solution:
    def missingInteger(self, nums):
        i = 1
        while i < len(nums) and nums[i] == nums[i - 1] + 1:
            i += 1
        total = sum(nums[:i])
        present = set(nums)
        x = total
        while x in present:
            x += 1
        return x

