var missingInteger = function(nums) {
    let i = 1;
    while (i < nums.length && nums[i] === nums[i - 1] + 1) {
        i++;
    }
    let total = 0;
    for (let j = 0; j < i; j++) total += nums[j];
    const present = new Set(nums);
    let x = total;
    while (present.has(x)) x++;
    return x;
};
